class Solution:
    def maxElementIndex(self, a: list[int]) -> int:
        s = []
        for i in range(len(a)):
            s.append(a[i])
            if len(s) > 1 and s[-1] < len(s):
                while s and s[-1] < len(s):
                    s.pop()
            if not s or s[-1] >= a[i]:
                s.append(a[i])
        if not s:
            return -1
        return s.index(max(s))

