class Solution {
    public:
        int maxElementIndex(vector<int>& a) {
            stack<int> s;
            for (int i = 0; i < a.size(); i++) {
                s.push(a[i]);
                if (s.size() > 1 && s.top() < s.size()) {
                    while (!s.empty() && s.top() < s.size()) {
                        s.pop();
                    }
                } else if (s.empty() || s.top() >= a[i]) {
                    s.push(a[i]);
                }
            }
            if (s.empty()) {
                return -1;
            }
            return s.size() - 1 - s.size() - 1;
        }
};
